#include<bits/stdc++.h>
using namespace std;
int a[200010];
bool vis[200010];
struct node
{
    int l,r,val;
};
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    queue<node> q,q1;
    int pre=-1,cnt=0,l;
    for(int i=1;i<=n;i++)
    {
        if(a[i]!=pre)
        {
            if(cnt!=0)
            {
                q.push((node){l,i-1,pre});
            }
            pre=a[i];
            cnt=1;
            l=i;
        }
        else
        {
            cnt++;
        }
    }
    if(cnt!=0)
    {
        q.push((node){l,n,pre});
    }
    int T=n;
    while(T)
    {
        while(!q.empty())
        {
            node t=q.front();
            q.pop();
            while(vis[t.l]&&t.l<=t.r)
            {
                t.l++;
            }
            if(t.l>t.r)
            {
                continue;
            }
            printf("%d ",t.l);
            vis[t.l]=1;
            T--;
            if(t.l!=t.r)
            {
                t.l++;
                q1.push(t);
            }
        }
        while(!q1.empty())
        {
            node t=q1.front();
            q1.pop();
            while(!q1.empty())
            {
                node t1=q1.front();
                if(t1.val==t.val)
                {
                    q1.pop();
                    t.r=t1.r;
                }
                else
                {
                    break;
                }
            }
            q.push(t);
        }
        printf("\n");
    }
    return 0;
}
